#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long L,R; scanf("%lld %lld", &L, &R);
        if(R <= 2*L-1) printf("%lld\n", R);
        else printf("-1\n");
    }
    return 0;
}

